import CustomCard from '../components/CustomCard';
import CollapsedText from '../components/CollapsedText';
import Button from '../components/CustomButton';

import "../styles/Home.css";
import ReactPlayer from 'react-player';
import { sparkle_game } from '../constants';

function Home() {

  return <div className='home-app'>

    <CustomCard content={<>
      <CustomCard content={<ReactPlayer
        url={sparkle_game.url}
        controls
        width='100%'
        height='100%'
        loop
        muted
        style={{ position: 'absolute', top: 0, left: 0 }}
      />} />

      <CustomCard content={
        <CollapsedText
          title={sparkle_game.title}
          description={sparkle_game.description}
          content={
            <Button
              buttonLabel={sparkle_game.buttonLabel}
              onClickNavigate="/game"
            />
          }
        />
      } /></>} />

  </div>
}

export default Home;
